class Solution {
    public long maxGCDScore(int[] nums, int k) {
        int n = nums.length;
        long[][] dp = new long[n + 1][k + 1];
        long maxScore = 0;
        for (int i = 0; i < n; i++) {
            int gcd = nums[i];
            for (int j = i; j >= 0; j--) {
                gcd = gcd(nums[j], gcd);
                long score = (long) (i - j + 1) * gcd;
                for (int op = 0; op <= k; op++) {
                    if (j == 0) {
                        maxScore = Math.max(maxScore, score + dp[j][op]);
                    } else {
                        dp[i + 1][op] = Math.max(dp[i + 1][op], score + dp[j - 1][op]);
                    }
                    if (op < k) {
                        score = Math.max(score, (long) (i - j + 1) * (gcd * 2));
                        if (j == 0) {
                            maxScore = Math.max(maxScore, score + dp[j][op + 1]);
                        } else {
                            dp[i + 1][op + 1] = Math.max(dp[i + 1][op + 1], score + dp[j - 1][op + 1]);
                        }
                    }
                }
            }
        }
        return maxScore;
    }

    int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }
}
